    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BST:
    def insert(self, val):
        # iterative insert

    def search(self, val):
        # iterative search

    def inorder(self, node, result=None):
        if result is None:
            result = []
        if node:
            self.inorder(node.left, result)
            result.append(node.val)
            self.inorder(node.right, result)
        return result

    # Optional: expose preorder/postorder as named methods
    def preorder(self, node, result=None):
        # for serialization/cloning
    def postorder(self, node, result=None):
        # for cleanup/memory management
```

The default method without arguments will be `inorder`. The other traversals will be available as named methods for their specific use cases.

**Recommendation: Use three-color DFS (white/gray/black)**

For directed graph cycle detection, three-color DFS is the correct and only suitable algorithm:

| Algorithm | Directed Graphs | Undirected Graphs | Notes |
|-----------|-----------------|-------------------|-------|
| Three-color DFS | ✓ Correct | ✓ Works | Detects back-edges to in-progress nodes |
| Parent-tracking DFS | ✗ Fails | ✓ Correct | Cannot distinguish back-edges from parent edges |
| Union-find | ✗ Fails | ✓ Correct | Treats edges as undirected relationships |

**Why three-color DFS works for directed graphs:**

```python
class DirectedGraph:
    WHITE, GRAY, BLACK = 0, 1, 2

    def has_cycle_dfs(self):
        color = {node: WHITE for node in self.adj}

        def dfs(node):
            color[node] = GRAY  # Mark as in-progress
            for neighbor in self.adj.get(node, []):
                if color[neighbor] == GRAY:
                    return True  # Back-edge → cycle detected
                if color[neighbor] == WHITE and dfs(neighbor):
                    return True
            color[node] = BLACK  # Mark as fully processed
            return False

        return any(dfs(node)

## Orchestrator Decision: BST Implementation Style (Recursive vs Iterative)

**Decision:** Implement core operations **recursively**, with a configurable recursion limit for safety.

**Rationale:**

| Factor | Recommendation | Reasoning |
|--------|----------------|-----------|
| **Readability** | Recursive ✓ | Mirrors tree structure naturally; much cleaner code |
| **Large trees** | Add safety guard | Default Python recursion limit (~1000) is sufficient for typical use cases |
| **Performance** | Negligible difference | Function call overhead minimal for balanced trees with <10k nodes |

**Implementation approach:**
```python
import sys

class BSTNode:
    __slots__ = ('value', 'left', 'right')  # Memory optimization

    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

class BST:
    def __init__(self, max_depth=None):
        self.root = None
        # Allow deeper trees if explicitly configured
        if max_depth:
            sys.setrecursionlimit(max_depth)

    def insert(self, val):
        self.root = self._insert_recursive(self.root, val)

    def _insert_recursive(self, node, val):
        if node is None:
            return BSTNode(val)
        if val < node.value:
            node.left = self._insert_recursive(node.left, val)
        elif val > node.value:
            node.right = self._insert_recursive(node.right, val)
        # val == node.value → no-op (duplicate rejection)
        return node

    def search(self, val):
        return self._search_recursive(self.root, val)

    def _search_recursive(self, node, val):
        if node is None:
            return False
        if val == node.value:
            return True
        elif val < node.value:
            return self._search_recursive(node.left, val

